from fastapi import APIRouter, Depends
from sqlalchemy.orm import Session

from app.api.deps import get_db
from app.schemas.report import RoomReportCreate, RoomReportResponse
from app.services.report import create_report, list_reports

router = APIRouter(prefix="/reports")


@router.post("", response_model=RoomReportResponse, status_code=201)
def submit_report(data: RoomReportCreate, db: Session = Depends(get_db)):
    return create_report(db, data)


@router.get("", response_model=list[RoomReportResponse])
def get_reports(room_id: str | None = None, db: Session = Depends(get_db)):
    return list_reports(db, room_id)

