/* ============================================================
   DESIGN SYSTEM — Housekeeping QR Report App
   Colors: #4A90FF primary · #E8F4FF card bg · #111 text
   Font: Nunito (Google Fonts)
   ============================================================ */

/* ---- CSS Variables ---- */
:root {
  --blue:        #4A90FF;
  --blue-dark:   #3a7fe0;
  --blue-light:  #E8F4FF;
  --blue-shadow: rgba(74, 144, 255, 0.15);
  --blue-glow:   rgba(74, 144, 255, 0.35);

  --text-primary:   #111111;
  --text-secondary: #333333;
  --text-muted:     #6B7280;
  --text-white:     #FFFFFF;

  --bg-gradient-start: #F8F9FB;
  --bg-gradient-end:   #FFFFFF;
  --card-white:     #FFFFFF;
  --border-light:   #E5EAF0;

  --radius-card:   20px;
  --radius-card-sm: 16px;
  --radius-thumb:  12px;
  --radius-btn:    26px;
  --radius-pill:   100px;

  --shadow-card:  0 8px 24px var(--blue-shadow);
  --shadow-btn:   0 4px 16px var(--blue-glow);
  --shadow-icon:  0 2px 12px rgba(0,0,0,0.10);

  --space-xs:  8px;
  --space-sm:  12px;
  --space-md:  16px;
  --space-lg:  24px;
  --space-xl:  32px;

  --btn-height:  52px;
  --icon-btn-sz: 48px;

  --font: 'Nunito', 'SF Pro Display', 'Roboto', sans-serif;
  --transition-screen: 300ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-press:  150ms ease;
}

/* ---- Reset ---- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html, body {
  height: 100%;
  overflow: hidden; /* SPA — each screen handles its own scroll */
}

body {
  font-family: var(--font);
  font-size: 14px;
  line-height: 1.6;
  color: var(--text-secondary);
  background: linear-gradient(180deg, var(--bg-gradient-start) 0%, var(--bg-gradient-end) 100%);
  -webkit-font-smoothing: antialiased;
  -webkit-tap-highlight-color: transparent;
  touch-action: manipulation;
}

/* ============================================================
   SCREEN SYSTEM
   ============================================================ */
.screen {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, var(--bg-gradient-start) 0%, var(--bg-gradient-end) 100%);
  /* Hidden by default */
  transform: translateX(100%);
  opacity: 0;
  pointer-events: none;
  transition: transform var(--transition-screen), opacity var(--transition-screen);
  will-change: transform, opacity;
  z-index: 1;
}

.screen--active {
  transform: translateX(0);
  opacity: 1;
  pointer-events: all;
  z-index: 2;
}

.screen--exit {
  transform: translateX(-30%);
  opacity: 0;
  pointer-events: none;
  z-index: 1;
}

.screen__inner {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  height: 100%;
}

.screen__inner--centered {
  justify-content: center;
  align-items: center;
}

/* ============================================================
   PAGE HEADER
   ============================================================ */
.page-header {
  padding: var(--space-lg) var(--space-md) var(--space-sm);
  flex-shrink: 0;
}

.page-header__title {
  font-size: 22px;
  font-weight: 800;
  color: var(--text-primary);
  line-height: 1.2;
}

.page-header__subtitle {
  font-size: 14px;
  font-weight: 400;
  color: var(--text-muted);
  margin-top: 4px;
}

.page-header--room {
  padding-bottom: var(--space-xs);
}

/* Room badge */
.room-badge {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: var(--blue);
  color: var(--text-white);
  font-size: 20px;
  font-weight: 800;
  letter-spacing: 0.04em;
  padding: 6px 20px;
  border-radius: var(--radius-pill);
  box-shadow: var(--shadow-btn);
}

/* ============================================================
   SCREEN CONTENT
   ============================================================ */
.screen-content {
  flex: 1;
  padding: var(--space-sm) var(--space-md) var(--space-md);
  display: flex;
  flex-direction: column;
  gap: var(--space-md);
  overflow: hidden;
}

.screen-content--scrollable {
  overflow-y: auto;
  -webkit-overflow-scrolling: touch;
}

.screen-content--center {
  justify-content: center;
  align-items: center;
  text-align: center;
  padding: var(--space-xl) var(--space-md);
}

/* ============================================================
   CARDS
   ============================================================ */
.card {
  border-radius: var(--radius-card);
  padding: var(--space-md);
}

.card--main {
  background: var(--blue-light);
  box-shadow: var(--shadow-card);
  padding: 20px;
}

.card--secondary {
  background: var(--card-white);
  border-radius: var(--radius-card-sm);
  box-shadow: 0 2px 8px rgba(0,0,0,0.06);
  padding: var(--space-sm) var(--space-md);
}

.card__title {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-primary);
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: var(--space-sm);
}

.card__title svg {
  color: var(--blue);
  flex-shrink: 0;
}

.card__label {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-muted);
  margin-bottom: var(--space-xs);
}

/* ============================================================
   BUTTONS
   ============================================================ */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: var(--btn-height);
  padding: 0 24px;
  border-radius: var(--radius-btn);
  font-family: var(--font);
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  border: none;
  outline: none;
  transition: transform var(--transition-press), background-color var(--transition-press), box-shadow var(--transition-press);
  -webkit-user-select: none;
  user-select: none;
  white-space: nowrap;
}

.btn:active {
  transform: scale(0.98);
}

.btn--primary {
  background: var(--blue);
  color: var(--text-white);
  box-shadow: var(--shadow-btn);
}
.btn--primary:active {
  background: var(--blue-dark);
  box-shadow: none;
}

.btn--secondary {
  background: var(--card-white);
  color: var(--blue);
  border: 2px solid var(--blue);
  box-shadow: none;
}
.btn--secondary:active {
  background: var(--blue-light);
}

.btn--full {
  width: 100%;
}

.btn--icon {
  width: var(--icon-btn-sz);
  height: var(--icon-btn-sz);
  border-radius: 50%;
  padding: 0;
  background: var(--card-white);
  box-shadow: var(--shadow-icon);
}

.btn--icon-only {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  padding: 0;
  flex-shrink: 0;
}

/* ============================================================
   INPUTS & TEXTAREAS
   ============================================================ */
.input, .textarea {
  width: 100%;
  font-family: var(--font);
  font-size: 15px;
  font-weight: 600;
  color: var(--text-primary);
  background: #F5F8FF;
  border: 2px solid var(--border-light);
  border-radius: 14px;
  padding: 12px 16px;
  outline: none;
  transition: border-color 200ms;
  resize: none;
}

.input:focus, .textarea:focus {
  border-color: var(--blue);
}

.input::placeholder, .textarea::placeholder {
  color: var(--text-muted);
  font-weight: 400;
}

/* ============================================================
   QR SCAN SCREEN
   ============================================================ */
.qr-wrapper {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex: 1;
  gap: var(--space-sm);
}

.qr-frame {
  position: relative;
  width: 100%;
  max-width: 320px;
  aspect-ratio: 4 / 3;
  border-radius: 20px;
  overflow: hidden;
  background: #000;
  box-shadow: 0 12px 32px rgba(0,0,0,0.25);
}

.qr-video {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.qr-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  opacity: 0;
  pointer-events: none;
}

/* Corner brackets */
.qr-corner {
  position: absolute;
  width: 28px;
  height: 28px;
  border-color: #FFFFFF;
  border-style: solid;
  z-index: 2;
}
.qr-corner--tl { top: 16px; left: 16px;  border-width: 3px 0 0 3px; border-radius: 4px 0 0 0; }
.qr-corner--tr { top: 16px; right: 16px; border-width: 3px 3px 0 0; border-radius: 0 4px 0 0; }
.qr-corner--bl { bottom: 16px; left: 16px;  border-width: 0 0 3px 3px; border-radius: 0 0 0 4px; }
.qr-corner--br { bottom: 16px; right: 16px; border-width: 0 3px 3px 0; border-radius: 0 0 4px 0; }

/* Scan line animation */
.qr-scanline {
  position: absolute;
  left: 16px; right: 16px;
  height: 2px;
  background: linear-gradient(90deg, transparent, var(--blue), transparent);
  border-radius: 2px;
  z-index: 2;
  animation: scan-move 2s ease-in-out infinite;
}
@keyframes scan-move {
  0%   { top: 20px;  opacity: 0; }
  10%  { opacity: 1; }
  90%  { opacity: 1; }
  100% { top: calc(100% - 20px); opacity: 0; }
}

/* Corner pulse */
.qr-frame::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 20px;
  box-shadow: inset 0 0 0 2px rgba(74,144,255,0.3);
  animation: frame-pulse 2s ease-in-out infinite;
  z-index: 2;
  pointer-events: none;
}
@keyframes frame-pulse {
  0%, 100% { box-shadow: inset 0 0 0 2px rgba(74,144,255,0.3); }
  50%       { box-shadow: inset 0 0 0 4px rgba(74,144,255,0.6); }
}

.qr-hint {
  font-size: 13px;
  color: var(--text-muted);
  text-align: center;
}

/* Manual entry row */
.manual-entry__row {
  display: flex;
  gap: var(--space-xs);
  align-items: center;
}

/* ============================================================
   CAMERA SCREEN
   ============================================================ */
.camera-wrapper {
  position: relative;
  width: 100%;
  aspect-ratio: 4 / 3;
  border-radius: var(--radius-card);
  overflow: hidden;
  background: #000;
  box-shadow: 0 12px 32px rgba(0,0,0,0.2);
  flex-shrink: 0;
}

.camera-video {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.camera-canvas { display: none; }

.camera-counter {
  position: absolute;
  top: 12px;
  right: 12px;
  background: rgba(0,0,0,0.55);
  color: #fff;
  font-family: var(--font);
  font-size: 14px;
  font-weight: 700;
  padding: 4px 12px;
  border-radius: var(--radius-pill);
  backdrop-filter: blur(4px);
  z-index: 2;
}

/* Shutter button */
.shutter-row {
  display: flex;
  justify-content: center;
  padding: 4px 0;
}

.shutter-btn {
  width: 72px;
  height: 72px;
  border-radius: 50%;
  background: #fff;
  border: 4px solid var(--blue);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  box-shadow: 0 4px 20px rgba(74,144,255,0.35);
  transition: transform var(--transition-press), box-shadow var(--transition-press);
}
.shutter-btn:active {
  transform: scale(0.94);
  box-shadow: none;
}

.shutter-inner {
  width: 52px;
  height: 52px;
  border-radius: 50%;
  background: var(--blue);
  display: block;
  transition: background var(--transition-press);
}
.shutter-btn:active .shutter-inner {
  background: var(--blue-dark);
}

/* Thumbnails */
.thumbnails-section { flex-shrink: 0; }

.section-label {
  font-size: 13px;
  font-weight: 700;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: var(--space-xs);
}

.thumbnails-row {
  display: flex;
  gap: var(--space-xs);
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  padding-bottom: 4px;
}
.thumbnails-row::-webkit-scrollbar { display: none; }

.thumb-item {
  position: relative;
  width: 72px;
  height: 72px;
  flex-shrink: 0;
  border-radius: var(--radius-thumb);
  overflow: hidden;
  box-shadow: 0 2px 8px rgba(0,0,0,0.12);
}

.thumb-item img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.thumb-delete {
  position: absolute;
  top: 4px;
  right: 4px;
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background: rgba(0,0,0,0.6);
  color: #fff;
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  line-height: 1;
  padding: 0;
}

/* Bottom actions row */
.bottom-actions {
  flex-shrink: 0;
  padding-bottom: env(safe-area-inset-bottom, 0px);
}

/* ============================================================
   REPORT SCREEN — Voice Card
   ============================================================ */
.voice-card {
  text-align: center;
}

.mic-wrapper {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-sm);
  padding: var(--space-sm) 0;
}

.mic-btn {
  position: relative;
  width: 88px;
  height: 88px;
  border-radius: 50%;
  background: var(--blue);
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 8px 24px var(--blue-glow);
  transition: transform var(--transition-press), box-shadow var(--transition-press);
  outline: none;
  -webkit-user-select: none;
  user-select: none;
}
.mic-btn:active {
  transform: scale(0.94);
  box-shadow: 0 4px 12px var(--blue-glow);
}

.mic-icon {
  color: #fff;
  position: relative;
  z-index: 2;
}

/* Ripple rings */
.mic-ripple {
  position: absolute;
  border-radius: 50%;
  border: 2px solid var(--blue);
  opacity: 0;
  animation: none;
}

.mic-ripple--1 { width: 110px; height: 110px; }
.mic-ripple--2 { width: 134px; height: 134px; }

/* Active recording state */
.mic-btn--recording {
  background: #FF4757;
  box-shadow: 0 8px 24px rgba(255,71,87,0.4);
}
.mic-btn--recording .mic-ripple--1 {
  border-color: #FF4757;
  animation: ripple 1.5s ease-out infinite;
}
.mic-btn--recording .mic-ripple--2 {
  border-color: #FF4757;
  animation: ripple 1.5s ease-out 0.5s infinite;
}
@keyframes ripple {
  0%   { transform: scale(0.8); opacity: 0.7; }
  100% { transform: scale(1.4); opacity: 0; }
}

.mic-status {
  font-size: 15px;
  font-weight: 700;
  color: var(--text-primary);
}

.transcript-label {
  font-size: 13px;
  font-weight: 700;
  color: var(--text-muted);
  text-align: left;
  margin-bottom: 6px;
}

/* Collapse button */
.collapse-btn {
  background: none;
  border: none;
  cursor: pointer;
  font-family: var(--font);
  font-size: 13px;
  font-weight: 600;
  color: var(--text-muted);
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 0;
}

/* Report screen thumbnails (horizontal) */
.report-thumbnails {
  display: flex;
  gap: var(--space-xs);
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  padding-bottom: 4px;
}
.report-thumbnails::-webkit-scrollbar { display: none; }

/* ============================================================
   STICKY CTA
   ============================================================ */
.sticky-cta {
  position: sticky;
  bottom: 0;
  padding: var(--space-sm) var(--space-md);
  padding-bottom: calc(var(--space-sm) + env(safe-area-inset-bottom, 0px));
  background: linear-gradient(to top, rgba(248,249,251,1) 60%, rgba(248,249,251,0));
  flex-shrink: 0;
}

.sticky-cta .btn--primary {
  font-size: 17px;
  letter-spacing: 0.04em;
}

/* ============================================================
   SUCCESS SCREEN
   ============================================================ */
.success-icon-wrapper {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 140px;
  height: 140px;
  margin: 0 auto var(--space-lg);
}

.success-circle {
  width: 88px;
  height: 88px;
  border-radius: 50%;
  background: var(--blue);
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 8px 28px var(--blue-glow);
  animation: pop-in 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) both;
  z-index: 2;
}

@keyframes pop-in {
  0%   { transform: scale(0); opacity: 0; }
  100% { transform: scale(1); opacity: 1; }
}

.success-check {
  animation: draw-check 0.4s ease 0.35s both;
}
@keyframes draw-check {
  0%   { stroke-dasharray: 60; stroke-dashoffset: 60; }
  100% { stroke-dasharray: 60; stroke-dashoffset: 0; }
}

.success-ring {
  position: absolute;
  border-radius: 50%;
  border: 2px solid var(--blue);
}
.success-ring--1 {
  width: 110px; height: 110px;
  animation: ring-expand 1s ease 0.5s both;
  opacity: 0.5;
}
.success-ring--2 {
  width: 134px; height: 134px;
  animation: ring-expand 1s ease 0.75s both;
  opacity: 0.25;
}
@keyframes ring-expand {
  0%   { transform: scale(0.6); opacity: 0.7; }
  100% { transform: scale(1);   opacity: 0; }
}

.success-title {
  font-size: 26px;
  font-weight: 800;
  color: var(--text-primary);
  line-height: 1.25;
  margin-bottom: var(--space-xs);
  animation: fade-up 0.4s ease 0.6s both;
}
.success-subtitle {
  font-size: 15px;
  color: var(--text-muted);
  margin-bottom: var(--space-md);
  animation: fade-up 0.4s ease 0.7s both;
}
@keyframes fade-up {
  0%   { transform: translateY(16px); opacity: 0; }
  100% { transform: translateY(0);    opacity: 1; }
}

.countdown-pill {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: var(--blue-light);
  color: var(--blue);
  font-size: 13px;
  font-weight: 700;
  padding: 6px 16px;
  border-radius: var(--radius-pill);
  margin-bottom: var(--space-md);
  animation: fade-up 0.4s ease 0.8s both;
}

/* ============================================================
   TOAST
   ============================================================ */
.toast {
  position: fixed;
  bottom: 96px;
  left: 50%;
  transform: translateX(-50%) translateY(20px);
  background: #222;
  color: #fff;
  font-family: var(--font);
  font-size: 14px;
  font-weight: 600;
  padding: 12px 20px;
  border-radius: var(--radius-pill);
  white-space: nowrap;
  opacity: 0;
  pointer-events: none;
  z-index: 1000;
  transition: opacity 0.25s, transform 0.25s;
  max-width: calc(100vw - 48px);
  text-align: center;
}

.toast--visible {
  opacity: 1;
  transform: translateX(-50%) translateY(0);
}

.toast--error   { background: #FF4757; }
.toast--success { background: #2ED573; color: #111; }

/* ============================================================
   LOADING SPINNER (submit state)
   ============================================================ */
.btn--loading {
  position: relative;
  pointer-events: none;
  opacity: 0.85;
}
.btn--loading::after {
  content: '';
  position: absolute;
  width: 20px;
  height: 20px;
  border: 2px solid rgba(255,255,255,0.4);
  border-top-color: #fff;
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}
@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ============================================================
   UTILITY
   ============================================================ */
.visually-hidden {
  position: absolute;
  width: 1px; height: 1px;
  overflow: hidden;
  clip: rect(0,0,0,0);
  white-space: nowrap;
}

/* ============================================================
   DESIGN SYSTEM — Housekeeping QR Report App
   Colors: #4A90FF primary · #E8F4FF card bg · #111 text
   Font: Nunito (Google Fonts)
   ============================================================ */

/* ---- CSS Variables ---- */
:root {
  --blue:        #4A90FF;
  --blue-dark:   #3a7fe0;
  --blue-light:  #E8F4FF;
  --blue-shadow: rgba(74, 144, 255, 0.15);
  --blue-glow:   rgba(74, 144, 255, 0.35);

  --text-primary:   #111111;
  --text-secondary: #333333;
  --text-muted:     #6B7280;
  --text-white:     #FFFFFF;

  --bg-gradient-start: #F8F9FB;
  --bg-gradient-end:   #FFFFFF;
  --card-white:     #FFFFFF;
  --border-light:   #E5EAF0;

  --radius-card:    20px;
  --radius-card-sm: 16px;
  --radius-thumb:   12px;
  --radius-btn:     26px;
  --radius-pill:    100px;

  --shadow-card:  0 8px 24px var(--blue-shadow);
  --shadow-btn:   0 4px 16px var(--blue-glow);
  --shadow-icon:  0 2px 12px rgba(0,0,0,0.10);

  --space-xs:  8px;
  --space-sm:  12px;
  --space-md:  16px;
  --space-lg:  24px;
  --space-xl:  32px;

  --btn-height:  52px;
  --icon-btn-sz: 48px;

  --font: 'Nunito', 'SF Pro Display', 'Roboto', sans-serif;
  --transition-screen: 300ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-press:  150ms ease;
}

/* ---- Reset ---- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html, body {
  height: 100%;
  overflow: hidden;
}

body {
  font-family: var(--font);
  font-size: 14px;
  line-height: 1.6;
  color: var(--text-secondary);
  background: linear-gradient(180deg, var(--bg-gradient-start) 0%, var(--bg-gradient-end) 100%);
  -webkit-font-smoothing: antialiased;
  -webkit-tap-highlight-color: transparent;
  touch-action: manipulation;
}

/* ============================================================
   SCREEN SYSTEM
   ============================================================ */
.screen {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, var(--bg-gradient-start) 0%, var(--bg-gradient-end) 100%);
  transform: translateX(100%);
  opacity: 0;
  pointer-events: none;
  transition: transform var(--transition-screen), opacity var(--transition-screen);
  will-change: transform, opacity;
  z-index: 1;
}

.screen--active {
  transform: translateX(0);
  opacity: 1;
  pointer-events: all;
  z-index: 2;
}

.screen--exit {
  transform: translateX(-30%);
  opacity: 0;
  pointer-events: none;
  z-index: 1;
}

.screen__inner {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  height: 100%;
}

.screen__inner--centered {
  justify-content: center;
  align-items: center;
}

/* ============================================================
   PAGE HEADER
   ============================================================ */
.page-header {
  padding: var(--space-lg) var(--space-md) var(--space-sm);
  flex-shrink: 0;
}

.page-header__title {
  font-size: 22px;
  font-weight: 800;
  color: var(--text-primary);
  line-height: 1.2;
}

.page-header__subtitle {
  font-size: 14px;
  font-weight: 400;
  color: var(--text-muted);
  margin-top: 4px;
}

.page-header--room {
  padding-bottom: var(--space-xs);
}

.room-badge {
  display: inline-flex;
  align-items: center;
  background: var(--blue);
  color: var(--text-white);
  font-size: 20px;
  font-weight: 800;
  letter-spacing: 0.04em;
  padding: 6px 20px;
  border-radius: var(--radius-pill);
  box-shadow: var(--shadow-btn);
}

/* ============================================================
   SCREEN CONTENT
   ============================================================ */
.screen-content {
  flex: 1;
  padding: var(--space-sm) var(--space-md) var(--space-md);
  display: flex;
  flex-direction: column;
  gap: var(--space-md);
  overflow: hidden;
}

.screen-content--scrollable {
  overflow-y: auto;
  -webkit-overflow-scrolling: touch;
}

.screen-content--center {
  justify-content: center;
  align-items: center;
  text-align: center;
  padding: var(--space-xl) var(--space-md);
}

/* ============================================================
   CARDS
   ============================================================ */
.card {
  border-radius: var(--radius-card);
  padding: var(--space-md);
}

.card--main {
  background: var(--blue-light);
  box-shadow: var(--shadow-card);
  padding: 20px;
}

.card--secondary {
  background: var(--card-white);
  border-radius: var(--radius-card-sm);
  box-shadow: 0 2px 8px rgba(0,0,0,0.06);
  padding: var(--space-sm) var(--space-md);
}

.card__title {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-primary);
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: var(--space-sm);
}

.card__title svg { color: var(--blue); flex-shrink: 0; }

.card__label {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-muted);
  margin-bottom: var(--space-xs);
}

/* ============================================================
   BUTTONS
   ============================================================ */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: var(--btn-height);
  padding: 0 24px;
  border-radius: var(--radius-btn);
  font-family: var(--font);
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  border: none;
  outline: none;
  transition: transform var(--transition-press), background-color var(--transition-press), box-shadow var(--transition-press);
  -webkit-user-select: none;
  user-select: none;
  white-space: nowrap;
}

.btn:active { transform: scale(0.98); }

.btn--primary {
  background: var(--blue);
  color: var(--text-white);
  box-shadow: var(--shadow-btn);
}
.btn--primary:active {
  background: var(--blue-dark);
  box-shadow: none;
}

.btn--secondary {
  background: var(--card-white);
  color: var(--blue);
  border: 2px solid var(--blue);
}
.btn--secondary:active { background: var(--blue-light); }

.btn--full { width: 100%; }

.btn--icon {
  width: var(--icon-btn-sz);
  height: var(--icon-btn-sz);
  border-radius: 50%;
  padding: 0;
  background: var(--card-white);
  box-shadow: var(--shadow-icon);
}

.btn--icon-only {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  padding: 0;
  flex-shrink: 0;
}

/* ============================================================
   INPUTS & TEXTAREAS
   ============================================================ */
.input, .textarea {
  width: 100%;
  font-family: var(--font);
  font-size: 15px;
  font-weight: 600;
  color: var(--text-primary);
  background: #F5F8FF;
  border: 2px solid var(--border-light);
  border-radius: 14px;
  padding: 12px 16px;
  outline: none;
  transition: border-color 200ms;
  resize: none;
}

.input:focus, .textarea:focus { border-color: var(--blue); }

.input::placeholder, .textarea::placeholder {
  color: var(--text-muted);
  font-weight: 400;
}

/* ============================================================
   QR SCAN SCREEN
   ============================================================ */
.qr-wrapper {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex: 1;
  gap: var(--space-sm);
}

.qr-frame {
  position: relative;
  width: 100%;
  max-width: 320px;
  aspect-ratio: 4 / 3;
  border-radius: 20px;
  overflow: hidden;
  background: #000;
  box-shadow: 0 12px 32px rgba(0,0,0,0.25);
}

.qr-video {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.qr-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  opacity: 0;
  pointer-events: none;
}

/* Corner brackets */
.qr-corner {
  position: absolute;
  width: 28px;
  height: 28px;
  border-color: #FFFFFF;
  border-style: solid;
  z-index: 2;
}
.qr-corner--tl { top: 16px; left: 16px;  border-width: 3px 0 0 3px; border-radius: 4px 0 0 0; }
.qr-corner--tr { top: 16px; right: 16px; border-width: 3px 3px 0 0; border-radius: 0 4px 0 0; }
.qr-corner--bl { bottom: 16px; left: 16px;  border-width: 0 0 3px 3px; border-radius: 0 0 0 4px; }
.qr-corner--br { bottom: 16px; right: 16px; border-width: 0 3px 3px 0; border-radius: 0 0 4px 0; }

/* Scan line */
.qr-scanline {
  position: absolute;
  left: 16px; right: 16px;
  height: 2px;
  background: linear-gradient(90deg, transparent, var(--blue), transparent);
  border-radius: 2px;
  z-index: 2;
  animation: scan-move 2s ease-in-out infinite;
}
@keyframes scan-move {
  0%   { top: 20px;  opacity: 0; }
  10%  { opacity: 1; }
  90%  { opacity: 1; }
  100% { top: calc(100% - 20px); opacity: 0; }
}

/* Frame pulse overlay */
.qr-frame::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 20px;
  box-shadow: inset 0 0 0 2px rgba(74,144,255,0.3);
  animation: frame-pulse 2s ease-in-out infinite;
  z-index: 2;
  pointer-events: none;
}
@keyframes frame-pulse {
  0%, 100% { box-shadow: inset 0 0 0 2px rgba(74,144,255,0.3); }
  50%       { box-shadow: inset 0 0 0 4px rgba(74,144,255,0.6); }
}

.qr-hint {
  font-size: 13px;
  color: var(--text-muted);
  text-align: center;
}

.manual-entry__row {
  display: flex;
  gap: var(--space-xs);
  align-items: center;
}

/* ============================================================
   CAMERA SCREEN
   ============================================================ */
.camera-wrapper {
  position: relative;
  width: 100%;
  aspect-ratio: 4 / 3;
  border-radius: var(--radius-card);
  overflow: hidden;
  background: #000;
  box-shadow: 0 12px 32px rgba(0,0,0,0.2);
  flex-shrink: 0;
}

.camera-video {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.camera-canvas { display: none; }

.camera-counter {
  position: absolute;
  top: 12px;
  right: 12px;
  background: rgba(0,0,0,0.55);
  color: #fff;
  font-family: var(--font);
  font-size: 14px;
  font-weight: 700;
  padding: 4px 12px;
  border-radius: var(--radius-pill);
  backdrop-filter: blur(4px);
  z-index: 2;
}

/* Shutter button */
.shutter-row {
  display: flex;
  justify-content: center;
  padding: 4px 0;
}

.shutter-btn {
  width: 72px;
  height: 72px;
  border-radius: 50%;
  background: #fff;
  border: 4px solid var(--blue);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  box-shadow: 0 4px 20px rgba(74,144,255,0.35);
  transition: transform var(--transition-press), box-shadow var(--transition-press);
}
.shutter-btn:active {
  transform: scale(0.94);
  box-shadow: none;
}

.shutter-inner {
  width: 52px;
  height: 52px;
  border-radius: 50%;
  background: var(--blue);
  display: block;
  transition: background var(--transition-press);
}
.shutter-btn:active .shutter-inner { background: var(--blue-dark); }

/* Thumbnails */
.thumbnails-section { flex-shrink: 0; }

.section-label {
  font-size: 13px;
  font-weight: 700;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: var(--space-xs);
}

.thumbnails-row {
  display: flex;
  gap: var(--space-xs);
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  padding-bottom: 4px;
}
.thumbnails-row::-webkit-scrollbar { display: none; }

.thumb-item {
  position: relative;
  width: 72px;
  height: 72px;
  flex-shrink: 0;
  border-radius: var(--radius-thumb);
  overflow: hidden;
  box-shadow: 0 2px 8px rgba(0,0,0,0.12);
}

.thumb-item img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.thumb-delete {
  position: absolute;
  top: 4px;
  right: 4px;
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background: rgba(0,0,0,0.6);
  color: #fff;
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  line-height: 1;
  padding: 0;
}

.bottom-actions {
  flex-shrink: 0;
  padding-bottom: env(safe-area-inset-bottom, 0px);
}

/* ============================================================
   REPORT SCREEN — Voice Card
   ============================================================ */
.voice-card { text-align: center; }

.mic-wrapper {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-sm);
  padding: var(--space-sm) 0;
}

.mic-btn {
  position: relative;
  width: 88px;
  height: 88px;
  border-radius: 50%;
  background: var(--blue);
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 8px 24px var(--blue-glow);
  transition: transform var(--transition-press), background-color var(--transition-press), box-shadow var(--transition-press);
  outline: none;
  -webkit-user-select: none;
  user-select: none;
}
.mic-btn:active {
  transform: scale(0.94);
  box-shadow: 0 4px 12px var(--blue-glow);
}

.mic-icon {
  color: #fff;
  position: relative;
  z-index: 2;
}

.mic-ripple {
  position: absolute;
  border-radius: 50%;
  border: 2px solid var(--blue);
  opacity: 0;
  animation: none;
}
.mic-ripple--1 { width: 110px; height: 110px; }
.mic-ripple--2 { width: 134px; height: 134px; }

.mic-btn--recording {
  background: #FF4757;
  box-shadow: 0 8px 24px rgba(255,71,87,0.4);
}
.mic-btn--recording .mic-ripple--1 {
  border-color: #FF4757;
  animation: ripple 1.5s ease-out infinite;
}
.mic-btn--recording .mic-ripple--2 {
  border-color: #FF4757;
  animation: ripple 1.5s ease-out 0.5s infinite;
}
@keyframes ripple {
  0%   { transform: scale(0.8); opacity: 0.7; }
  100% { transform: scale(1.4); opacity: 0; }
}

.mic-status {
  font-size: 15px;
  font-weight: 700;
  color: var(--text-primary);
}

.transcript-label {
  font-size: 13px;
  font-weight: 700;
  color: var(--text-muted);
  text-align: left;
  margin-bottom: 6px;
}

.collapse-btn {
  background: none;
  border: none;
  cursor: pointer;
  font-family: var(--font);
  font-size: 13px;
  font-weight: 600;
  color: var(--text-muted);
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 0;
}

.report-thumbnails {
  display: flex;
  gap: var(--space-xs);
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  padding-bottom: 4px;
}
.report-thumbnails::-webkit-scrollbar { display: none; }

/* ============================================================
   STICKY CTA
   ============================================================ */
.sticky-cta {
  position: sticky;
  bottom: 0;
  padding: var(--space-sm) var(--space-md);
  padding-bottom: calc(var(--space-sm) + env(safe-area-inset-bottom, 0px));
  background: linear-gradient(to top, rgba(248,249,251,1) 60%, rgba(248,249,251,0));
  flex-shrink: 0;
}

.sticky-cta .btn--primary {
  font-size: 17px;
  letter-spacing: 0.04em;
}

/* ============================================================
   SUCCESS SCREEN
   ============================================================ */
.success-icon-wrapper {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 140px;
  height: 140px;
  margin: 0 auto var(--space-lg);
}

.success-circle {
  width: 88px;
  height: 88px;
  border-radius: 50%;
  background: var(--blue);
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 8px 28px var(--blue-glow);
  animation: pop-in 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) both;
  z-index: 2;
}
@keyframes pop-in {
  0%   { transform: scale(0); opacity: 0; }
  100% { transform: scale(1); opacity: 1; }
}

.success-check {
  animation: draw-check 0.4s ease 0.35s both;
}
@keyframes draw-check {
  from { stroke-dasharray: 60; stroke-dashoffset: 60; }
  to   { stroke-dasharray: 60; stroke-dashoffset: 0; }
}

.success-ring {
  position: absolute;
  border-radius: 50%;
  border: 2px solid var(--blue);
}
.success-ring--1 {
  width: 110px; height: 110px;
  animation: ring-expand 1s ease 0.5s both;
}
.success-ring--2 {
  width: 134px; height: 134px;
  animation: ring-expand 1s ease 0.75s both;
}
@keyframes ring-expand {
  0%   { transform: scale(0.6); opacity: 0.6; }
  100% { transform: scale(1.1); opacity: 0; }
}

.success-title {
  font-size: 26px;
  font-weight: 800;
  color: var(--text-primary);
  line-height: 1.25;
  margin-bottom: var(--space-xs);
  animation: fade-up 0.4s ease 0.6s both;
}
.success-subtitle {
  font-size: 15px;
  color: var(--text-muted);
  margin-bottom: var(--space-md);
  animation: fade-up 0.4s ease 0.7s both;
}
@keyframes fade-up {
  0%   { transform: translateY(16px); opacity: 0; }
  100% { transform: translateY(0);    opacity: 1; }
}

.countdown-pill {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: var(--blue-light);
  color: var(--blue);
  font-size: 13px;
  font-weight: 700;
  padding: 6px 16px;
  border-radius: var(--radius-pill);
  margin-bottom: var(--space-md);
  animation: fade-up 0.4s ease 0.8s both;
}

/* ============================================================
   TOAST
   ============================================================ */
.toast {
  position: fixed;
  bottom: 96px;
  left: 50%;
  transform: translateX(-50%) translateY(20px);
  background: #222;
  color: #fff;
  font-family: var(--font);
  font-size: 14px;
  font-weight: 600;
  padding: 12px 20px;
  border-radius: var(--radius-pill);
  white-space: nowrap;
  opacity: 0;
  pointer-events: none;
  z-index: 1000;
  transition: opacity 0.25s, transform 0.25s;
  max-width: calc(100vw - 48px);
  text-align: center;
  text-overflow: ellipsis;
  overflow: hidden;
}
.toast--visible { opacity: 1; transform: translateX(-50%) translateY(0); }
.toast--error   { background: #FF4757; }
.toast--success { background: #2ED573; color: #111; }

/* ============================================================
   LOADING STATE
   ============================================================ */
.btn--loading {
  position: relative;
  pointer-events: none;
  opacity: 0.85;
}
.btn--loading span,
.btn--loading svg { opacity: 0; }
.btn--loading::after {
  content: '';
  position: absolute;
  width: 20px;
  height: 20px;
  border: 2px solid rgba(255,255,255,0.4);
  border-top-color: #fff;
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

