   DESIGN SYSTEM — Housekeeping QR Report App
   Colors: #4A90FF primary · #E8F4FF card bg · #111 text
   Font: Nunito (Google Fonts)
   ============================================================ */

/* ---- CSS Variables ---- */
:root {
  --blue:        #4A90FF;
  --blue-dark:   #3a7fe0;
  --blue-light:  #E8F4FF;
  --blue-shadow: rgba(74, 144, 255, 0.15);
  --blue-glow:   rgba(74, 144, 255, 0.35);

  --text-primary:   #111111;
  --text-secondary: #333333;
  --text-muted:     #6B7280;
  --text-white:     #FFFFFF;

  --bg-gradient-start: #F8F9FB;
  --bg-gradient-end:   #FFFFFF;
  --card-white:     #FFFFFF;
  --border-light:   #E5EAF0;

  --radius-card:    20px;
  --radius-card-sm: 16px;
  --radius-thumb:   12px;
  --radius-btn:     26px;
  --radius-pill:    100px;

  --shadow-card:  0 8px 24px var(--blue-shadow);
  --shadow-btn:   0 4px 16px var(--blue-glow);
  --shadow-icon:  0 2px 12px rgba(0,0,0,0.10);

  --space-xs:  8px;
  --space-sm:  12px;
  --space-md:  16px;
  --space-lg:  24px;
  --space-xl:  32px;

  --btn-height:  52px;
  --icon-btn-sz: 48px;

  --font: 'Nunito', 'SF Pro Display', 'Roboto', sans-serif;
  --transition-screen: 300ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-press:  150ms ease;
}

/* ---- Reset ---- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html, body {
  height: 100%;
  overflow: hidden;
}

body {
  font-family: var(--font);
  font-size: 14px;
  line-height: 1.6;
  color: var(--text-secondary);
  background: linear-gradient(180deg, var(--bg-gradient-start) 0%, var(--bg-gradient-end) 100%);
  -webkit-font-smoothing: antialiased;
  -webkit-tap-highlight-color: transparent;
  touch-action: manipulation;
}

/* ============================================================
   SCREEN SYSTEM
   ============================================================ */
.screen {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, var(--bg-gradient-start) 0%, var(--bg-gradient-end) 100%);
  transform: translateX(100%);
  opacity: 0;
  pointer-events: none;
  transition: transform var(--transition-screen), opacity var(--transition-screen);
  will-change: transform, opacity;
  z-index: 1;
}

.screen--active {
  transform: translateX(0);
  opacity: 1;
  pointer-events: all;
  z-index: 2;
}

.screen--exit {
  transform: translateX(-30%);
  opacity: 0;
  pointer-events: none;
  z-index: 1;
}

.screen__inner {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  height: 100%;
}

.screen__inner--centered {
  justify-content: center;
  align-items: center;
}

/* ============================================================
   PAGE HEADER
   ============================================================ */
.page-header {
  padding: var(--space-lg) var(--space-md) var(--space-sm);
  flex-shrink: 0;
}

.page-header__title {
  font-size: 22px;
  font-weight: 800;
  color: var(--text-primary);
  line-height: 1.2;
}

.page-header__subtitle {
  font-size: 14px;
  font-weight: 400;
  color: var(--text-muted);
  margin-top: 4px;
}

.page-header--room {
  padding-bottom: var(--space-xs);
}

.room-badge {
  display: inline-flex;
  align-items: center;
  background: var(--blue);
  color: var(--text-white);
  font-size: 20px;
  font-weight: 800;
  letter-spacing: 0.04em;
  padding: 6px 20px;
  border-radius: var(--radius-pill);
  box-shadow: var(--shadow-btn);
}

/* ============================================================
   SCREEN CONTENT
   ============================================================ */
.screen-content {
  flex: 1;
  padding: var(--space-sm) var(--space-md) var(--space-md);
  display: flex;
  flex-direction: column;
  gap: var(--space-md);
  overflow: hidden;
}

.screen-content--scrollable {
  overflow-y: auto;
  -webkit-overflow-scrolling: touch;
}

.screen-content--center {
  justify-content: center;
  align-items: center;
  text-align: center;
  padding: var(--space-xl) var(--space-md);
}

/* ============================================================
   CARDS
   ============================================================ */
.card {
  border-radius: var(--radius-card);
  padding: var(--space-md);
}

.card--main {
  background: var(--blue-light);
  box-shadow: var(--shadow-card);
  padding: 20px;
}

.card--secondary {
  background: var(--card-white);
  border-radius: var(--radius-card-sm);
  box-shadow: 0 2px 8px rgba(0,0,0,0.06);
  padding: var(--space-sm) var(--space-md);
}

.card__title {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-primary);
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: var(--space-sm);
}

.card__title svg { color: var(--blue); flex-shrink: 0; }

.card__label {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-muted);
  margin-bottom: var(--space-xs);
}

/* ============================================================
   BUTTONS
   ============================================================ */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: var(--btn-height);
  padding: 0 24px;
  border-radius: var(--radius-btn);
  font-family: var(--font);
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  border: none;
  outline: none;
  transition: transform var(--transition-press), background-color var(--transition-press), box-shadow var(--transition-press);
  -webkit-user-select: none;
  user-select: none;
  white-space: nowrap;
}

.btn:active { transform: scale(0.98); }

.btn--primary {
  background: var(--blue);
  color: var(--text-white);
  box-shadow: var(--shadow-btn);
}
.btn--primary:active {
  background: var(--blue-dark);
  box-shadow: none;
}

.btn--secondary {
  background: var(--card-white);
  color: var(--blue);
  border: 2px solid var(--blue);
}
.btn--secondary:active { background: var(--blue-light); }

.btn--full { width: 100%; }

.btn--icon {
  width: var(--icon-btn-sz);
  height: var(--icon-btn-sz);
  border-radius: 50%;
  padding: 0;
  background: var(--card-white);
  box-shadow: var(--shadow-icon);
}

.btn--icon-only {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  padding: 0;
  flex-shrink: 0;
}

/* ============================================================
   INPUTS & TEXTAREAS
   ============================================================ */
.input, .textarea {
  width: 100%;
  font-family: var(--font);
  font-size: 15px;
  font-weight: 600;
  color: var(--text-primary);
  background: #F5F8FF;
  border: 2px solid var(--border-light);
  border-radius: 14px;
  padding: 12px 16px;
  outline: none;
  transition: border-color 200ms;
  resize: none;
}

.input:focus, .textarea:focus { border-color: var(--blue); }

.input::placeholder, .textarea::placeholder {
  color: var(--text-muted);
  font-weight: 400;
}

/* ============================================================
   QR SCAN SCREEN
   ============================================================ */
.qr-wrapper {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex: 1;
  gap: var(--space-sm);
}

.qr-frame {
  position: relative;
  width: 100%;
  max-width: 320px;
  aspect-ratio: 4 / 3;
  border-radius: 20px;
  overflow: hidden;
  background: #000;
  box-shadow: 0 12px 32px rgba(0,0,0,0.25);
}

.qr-video {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.qr-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  opacity: 0;
  pointer-events: none;
}

/* Corner brackets */
.qr-corner {
  position: absolute;
  width: 28px;
  height: 28px;
  border-color: #FFFFFF;
  border-style: solid;
  z-index: 2;
}
.qr-corner--tl { top: 16px; left: 16px;  border-width: 3px 0 0 3px; border-radius: 4px 0 0 0; }
.qr-corner--tr { top: 16px; right: 16px; border-width: 3px 3px 0 0; border-radius: 0 4px 0 0; }
.qr-corner--bl { bottom: 16px; left: 16px;  border-width: 0 0 3px 3px; border-radius: 0 0 0 4px; }
.qr-corner--br { bottom: 16px; right: 16px; border-width: 0 3px 3px 0; border-radius: 0 0 4px 0; }

/* Scan line */
.qr-scanline {
  position: absolute;
  left: 16px; right: 16px;
  height: 2px;
  background: linear-gradient(90deg, transparent, var(--blue), transparent);
  border-radius: 2px;
  z-index: 2;
  animation: scan-move 2s ease-in-out infinite;
}
@keyframes scan-move {
  0%   { top: 20px;  opacity: 0; }
  10%  { opacity: 1; }
  90%  { opacity: 1; }
  100% { top: calc(100% - 20px); opacity: 0; }
}

/* Frame pulse overlay */
.qr-frame::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 20px;
  box-shadow: inset 0 0 0 2px rgba(74,144,255,0.3);
  animation: frame-pulse 2s ease-in-out infinite;
  z-index: 2;
  pointer-events: none;
}
@keyframes frame-pulse {
  0%, 100% { box-shadow: inset 0 0 0 2px rgba(74,144,255,0.3); }
  50%       { box-shadow: inset 0 0 0 4px rgba(74,144,255,0.6); }
}

.qr-hint {
  font-size: 13px;
  color: var(--text-muted);
  text-align: center;
}

.manual-entry__row {
  display: flex;
  gap: var(--space-xs);
  align-items: center;
}

/* ============================================================
   CAMERA SCREEN
   ============================================================ */
.camera-wrapper {
