/**
 * Housekeeping QR Report — Main App
 * Screens: qr → camera → report → success
 */

// ============================================================
// STATE
// ============================================================
const state = {
  currentScreen: 'qr',
  roomId: null,
  photos: [],        // { blob, dataUrl, s3Url }
  voiceText: '',
  qrStream: null,
  cameraStream: null,
  recognition: null,
  isRecording: false,
  countdownTimer: null,
};

// ============================================================
// UTILS
// ============================================================
function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

let toastTimer = null;
function showToast(message, type = 'default') {
  const toast = document.getElementById('toast');
  toast.textContent = message;
  toast.className = 'toast toast--visible';
  if (type === 'error')   toast.classList.add('toast--error');
  if (type === 'success') toast.classList.add('toast--success');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => {
    toast.classList.remove('toast--visible');
  }, 2800);
}

// ============================================================
// SCREEN NAVIGATION
// ============================================================
function navigateTo(screenName) {
  const current = document.querySelector('.screen--active');
  const next = document.getElementById(`screen-${screenName}`);
  if (!next || current === next) return;

  // Lifecycle: leaving current screen
  if (state.currentScreen === 'qr')     stopQRScanner();
  if (state.currentScreen === 'camera') stopCamera();

  current.classList.remove('screen--active');
  current.classList.add('screen--exit');
  next.classList.add('screen--active');

  setTimeout(() => {
    current.classList.remove('screen--exit');
  }, 320);

  state.currentScreen = screenName;

  // Lifecycle: entering next screen
  if (screenName === 'qr')      initQRScreen();
  if (screenName === 'camera')  initCameraScreen();
  if (screenName === 'success') initSuccessScreen();
}

// ============================================================
// SCREEN 1 — QR SCAN
// ============================================================
function initQRScreen() {
  startQRScanner();
}

async function startQRScanner() {
  const video = document.getElementById('qr-video');
  try {
    const stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: { ideal: 'environment' }, width: { ideal: 1280 }, height: { ideal: 960 } }
    });
    video.srcObject = stream;
    state.qrStream = stream;
    video.addEventListener('loadedmetadata', () => {
      video.play();
      requestAnimationFrame(scanQRFrame);
    }, { once: true });
  } catch (err) {
    showToast('Không thể mở camera QR. Nhập mã thủ công.', 'error');
  }
}

function scanQRFrame() {
  if (state.currentScreen !== 'qr') return;

  const video = document.getElementById('qr-video');
  const canvas = document.getElementById('qr-canvas');
  const ctx = canvas.getContext('2d');

  if (video.readyState === video.HAVE_ENOUGH_DATA) {
    canvas.width  = video.videoWidth;
    canvas.height = video.videoHeight;
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);

    if (typeof jsQR !== 'undefined') {
      const code = jsQR(imageData.data, imageData.width, imageData.height, {
        inversionAttempts: 'dontInvert',
      });
      if (code && code.data) {
        const roomId = code.data.trim();
        handleRoomIdFound(roomId);
        return;
      }
    }
  }

  requestAnimationFrame(scanQRFrame);
}

function handleRoomIdFound(roomId) {
  state.roomId = roomId;
  stopQRScanner();

  // Update UI for camera screen
  document.getElementById('camera-room-badge').textContent = `PHÒNG ${escapeHtml(roomId)}`;
  document.getElementById('report-room-badge').textContent  = `PHÒNG ${escapeHtml(roomId)}`;
  document.getElementById('success-room-name').textContent  = roomId;

  // Reset photos
  state.photos = [];

  navigateTo('camera');
}

function stopQRScanner() {
  if (state.qrStream) {
    state.qrStream.getTracks().forEach(t => t.stop());
    state.qrStream = null;
    const video = document.getElementById('qr-video');
    if (video) video.srcObject = null;
  }
}

// Manual entry
document.getElementById('manual-submit-btn').addEventListener('click', () => {
  const input = document.getElementById('manual-room-input');
  const val = input.value.trim();
  if (!val) {
    showToast('Vui lòng nhập mã phòng', 'error');
    input.focus();
    return;
  }
  input.value = '';
  handleRoomIdFound(val);
});

document.getElementById('manual-room-input').addEventListener('keydown', (e) => {
  if (e.key === 'Enter') document.getElementById('manual-submit-btn').click();
});

document.getElementById('start-scan-btn').addEventListener('click', () => {
  if (!state.qrStream) startQRScanner();
});

// ============================================================
// SCREEN 2 — CAMERA CAPTURE
// ============================================================
async function initCameraScreen() {
  state.photos = [];
  updateCameraUI();
  await startCamera();
}

async function startCamera() {
  const video = document.getElementById('camera-video');
  try {
    const stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: { ideal: 'environment' }, width: { ideal: 1280 }, height: { ideal: 960 } }
    });
    video.srcObject = stream;
    state.cameraStream = stream;
    video.play();
  } catch (err) {
    showToast('Không thể mở camera', 'error');
  }
}

function stopCamera() {
  if (state.cameraStream) {
    state.cameraStream.getTracks().forEach(t => t.stop());
    state.cameraStream = null;
    const video = document.getElementById('camera-video');
    if (video) video.srcObject = null;
  }
}

function capturePhoto() {
  if (state.photos.length >= 3) return;

  const video  = document.getElementById('camera-video');
  const canvas = document.getElementById('camera-canvas');

  canvas.width  = video.videoWidth  || 640;
  canvas.height = video.videoHeight || 480;
  const ctx = canvas.getContext('2d');
  ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

  canvas.toBlob((blob) => {
    const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
    state.photos.push({ blob, dataUrl, s3Url: null });
    updateCameraUI();

    if (state.photos.length === 3) {
      // Auto-navigate after brief delay to show thumbnail
      setTimeout(() => transitionToReport(), 600);
    }
  }, 'image/jpeg', 0.85);
}

function deletePhoto(index) {
  state.photos.splice(index, 1);
  updateCameraUI();
}

function updateCameraUI() {
  const count = state.photos.length;
  document.getElementById('camera-counter').textContent = `${count} / 3`;

  const thumbsRow  = document.getElementById('thumbnails-row');
  const thumbsSect = document.getElementById('thumbnails-section');
  const bottomActs = document.getElementById('camera-bottom-actions');

  // Render thumbnails
  if (count > 0) {
    thumbsSect.style.display = '';
    thumbsRow.innerHTML = state.photos.map((p, i) => `
      <div class="thumb-item">
        <img src="${p.dataUrl}" alt="Ảnh ${i + 1}" />
        <button class="thumb-delete" data-index="${i}" aria-label="Xóa ảnh ${i + 1}">×</button>
      </div>
    `).join('');
  } else {
