function navigateTo(screenName) {
  const current = document.querySelector('.screen--active');
  const next = document.getElementById(`screen-${screenName}`);
  if (!next || current === next) return;

  // Lifecycle: leaving current screen
  if (state.currentScreen === 'qr')     stopQRScanner();
  if (state.currentScreen === 'camera') stopCamera();

  current.classList.remove('screen--active');
  current.classList.add('screen--exit');
  next.classList.add('screen--active');

  setTimeout(() => {
    current.classList.remove('screen--exit');
  }, 320);

  state.currentScreen = screenName;

